class FixedSerializer(JsonPlusSerializer):
    def _msgpack_enc(self, obj):
        if isinstance(obj, Send):
            # Convert Send to a serializable dictionary with a marker
            return {"__langgraph_send__": True, "node": obj.node, "arg": obj.arg}
        return super()._msgpack_enc(obj)

    def loads_typed(self, data: bytes):
        # Decode using the parent method
        obj = super().loads_typed(data)

        # Recursive restore function to reconstruct Send objects
        def _restore(item):
            if isinstance(item, dict) and item.get("__langgraph_send__"):
                return Send(node=item["node"], arg=item["arg"])
            if isinstance(item, list):
                return [_restore(x) for x in item]
            if isinstance(item, dict):
                return {k: _restore(v) for k, v in item.items()}
            return item

        return _restore(obj)

