def _handle_list_namespaces(self, op):
    try:
        namespaces = self._get_namespaces()  # Returns: [("user1", "form1"), (None, "form2")]

        # Filter out namespaces with None values to prevent sorting errors
        valid_namespaces = {
            ns[: op.max_depth] 
            for ns in namespaces 
            if all(n is not None for n in ns[:op.max_depth])
        }

        namespaces = sorted(valid_namespaces)
        return namespaces
    except Exception as e:
        log.error(f"Error handling list namespaces: {e}")
        # Fallback: return only non-None namespaces
        namespaces = self._get_namespaces()
        valid_namespaces = []
        for ns in namespaces:
            try:
                sub_ns = ns[:op.max_depth]
                if all(n is not None for n in sub_ns):
                    valid_namespaces.append(sub_ns)
            except:
                continue
        return sorted(valid_namespaces)

